#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, Q;
        scanf("%d %d", &N, &Q);
        int L[N], K[Q];
        for (int i = 0; i < N; i++) {
            scanf("%d", &L[i]);
        }
        for (int i = 0; i < Q; i++) {
            scanf("%d", &K[i]);
        }
        qsort(L, N, sizeof(int), compare);
        qsort(K, Q, sizeof(int), compare);
        for (int i = 0; i < Q; i++) {
            int count = 0;
            int j = N - 1;
            while (j >= 0 && L[j] >= K[i]) {
                count++;
                j--;
            }
            printf("%d\n", count);
        }
    }
    return 0;
}

