code.Java:
import java.util.Arrays;
import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int Q = sc.nextInt();
            int[] L = new int[N];
            int[] K = new int[Q];
            for (int i = 0; i < N; i++) {
                L[i] = sc.nextInt();
            }
            for (int i = 0; i < Q; i++) {
                K[i] = sc.nextInt();
            }
            Arrays.sort(L);
            Arrays.sort(K);
            for (int i = 0; i < Q; i++) {
                int count = 0;
                int j = N - 1;
                while (j >= 0 && L[j] >= K[i]) {
                    count++;
                    j--;
                }
                System.out.println(count);
            }
        }
    }
}

