const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

function nextInt() {
    return parseInt(lines[idx++]);
}

function nextIntArray() {
    return lines[idx++].trim().split(' ').map(Number);
}

let T = nextInt();
while (T-- > 0) {
    let [N, Q] = nextIntArray();
    let L = nextIntArray();
    let K = [];
    for (let i = 0; i < Q; i++) {
        K.push(nextInt());
    }
    L.sort((a, b) => a - b);
    K.sort((a, b) => a - b);
    for (let i = 0; i < Q; i++) {
        let count = 0;
        let j = N - 1;
        while (j >= 0 && L[j] >= K[i]) {
            count++;
            j--;
        }
        console.log(count);
    }
}

